function openBoltTable(){
  const tbody=ge('bolt-table-body');
  if(!tbody.children.length){
    const gr=GRADE['8.8'];
    const {mt,mw}=MU_MAP['dry'];
    const bolts=Object.keys(BOLT).map(Number).sort((a,b)=>a-b);
    tbody.innerHTML=bolts.map(d=>{
      const b=BOLT[d];
      const Db=(b.dw+b.dh)/2;
      const K=b.p/(2*Math.PI*d)+0.577*mt*b.d2/d+mw*Db/(2*d);
      const Knd=K*d;
      const At=b.p/(2*Math.PI)+0.577*mt*b.d2;
      const dAs=Math.sqrt(4*b.As/Math.PI);
      const Fy_denom=1+3*Math.pow(3/dAs*At,2);
      const Fy=gr.Sy*b.As/Math.sqrt(Fy_denom)/1000;
      const T_rec=(Knd*Fy/1.5).toFixed(2);
      return `<tr><td>M${d}</td><td>${b.p.toFixed(2)}</td><td>${T_rec}</td><td>${b.As}</td></tr>`;
    }).join('');
  }
  ge('bolttable-modal').style.display='flex';
}

function closeBoltTable(){
  ge('bolttable-modal').style.display='none';
}

